const decode = b64 => Buffer.from(b64, 'base64').toString('utf8').trim();
const accessToken = decode($('Get access_token').first().json.payload.data);
const adAccountId = decode($('Get ad_account_id').first().json.payload.data);
const client = $('Loop over clients').item.json;
const API_VERSION = 'v22.0';
return [{ json: {
  client_id: client.client_id, slug: client.slug, currency: client.currency,
  access_token: accessToken, ad_account_id: adAccountId, api_version: API_VERSION
}}];

const ctx = $('Decode secrets').first().json;
const CLIENT_ID = ctx.client_id;
const AD_ACCOUNT = ctx.ad_account_id;
const INGESTED_AT = new Date().toISOString();
const num = v => (v === null || v === undefined || v === '' ? null : Number(v));
const pick = (arr, type) => {
  if (!Array.isArray(arr)) return null;
  const row = arr.find(a => a.action_type === type);
  return row ? Number(row.value) : null;
};
const all = [];
for (const it of $input.all()) {
  for (const r of (it.json.data || [])) all.push(r);
}
return all.map(r => ({ json: {
  client_id: CLIENT_ID,
  ingested_at: INGESTED_AT,
  ingest_source: 'cron',
  ad_account_id: AD_ACCOUNT,
  campaign_id: String(r.campaign_id),
  campaign_name: r.campaign_name ?? '',
  date_start: r.date_start,
  date_stop: r.date_stop,
  spend: num(r.spend),
  impressions: num(r.impressions),
  reach: num(r.reach),
  frequency: num(r.frequency),
  clicks: num(r.clicks),
  ctr: num(r.ctr),
  cpc: num(r.cpc),
  purchases:          pick(r.actions, 'omni_purchase') ?? pick(r.actions, 'purchase'),
  purchase_value:     pick(r.action_values, 'omni_purchase') ?? pick(r.action_values, 'purchase'),
  add_to_cart:        pick(r.actions, 'add_to_cart'),
  initiate_checkout:  pick(r.actions, 'initiate_checkout'),
  landing_page_views: pick(r.actions, 'landing_page_view'),
  link_clicks:        pick(r.actions, 'link_click'),
  video_views:        pick(r.actions, 'video_view'),
  purchase_roas:      pick(r.purchase_roas, 'omni_purchase'),
  actions:       (r.actions       || []).map(a => ({ action_type: a.action_type, value: Number(a.value) })),
  action_values: (r.action_values || []).map(a => ({ action_type: a.action_type, value: Number(a.value) })),
  payload_json: JSON.stringify(r)
}}));

